queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?source_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:source_id ?cg . ?child a :Sources ; p:source_id ?cg . ?l p:recruiter_id ?pg . ?parent a :Recruiters ; p:recruiter_id ?pg . } GROUP BY ?child }
  ?child p:source_name ?source_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Recruiters } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?source_name WHERE {
  ?recruiters_sources a :Recruiters_Sources .
  ?sources a :Sources .
  ?recruiters_sources p:hasSources ?sources .
  ?recruiters a :Recruiters .
  ?recruiters_sources p:hasRecruiters ?recruiters .
  ?recruiters p:name ?name .
  ?sources p:source_name ?source_name .
} }
  collective: { SELECT ?source_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:source_id ?cg . ?child a :Sources ; p:source_id ?cg . ?l p:recruiter_id ?pg . ?parent a :Recruiters ; p:recruiter_id ?pg . } GROUP BY ?child }
  ?child p:source_name ?source_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Recruiters } }
  FILTER(?nf = ?total)
} }
}
